import i18n from 'i18next';
import { initReactI18next } from 'react-i18next';
import LanguageDetector from 'i18next-browser-languagedetector';

const resources = {
  fr: {
    translation: {
      'nav.home': 'Accueil',
      'nav.proposals': 'Propositions',
      'nav.statistics': 'Statistiques',
      'nav.login': 'Se connecter',
      'nav.register': 'Créer un compte',
      'nav.logout': 'Se déconnecter',
      'home.hero.title': 'MAONI',
      'home.hero.subtitle': 'Plateforme nationale',
      'home.hero.cta': 'Participer',
      'home.citizens': 'Citoyens',
      'home.proposals': 'Propositions',
      'home.votes': 'Votes',
      'proposals.title': 'Propositions',
      'proposals.submit': 'Soumettre',
      'proposals.filter.all': 'Toutes',
      'proposals.filter.yes': 'OUI',
      'proposals.filter.no': 'NON',
      'proposals.sort.recent': 'Récent',
      'proposals.sort.popular': 'Populaire',
      'proposals.sort.controversial': 'Contesté',
      'stats.title': 'Statistiques',
      'auth.email': 'Email',
      'auth.password': 'Mot de passe',
      'auth.firstName': 'Prénom',
      'auth.lastName': 'Nom',
      'auth.phone': 'Téléphone',
      'auth.province': 'Province',
      'auth.age': 'Âge',
      'auth.profession': 'Profession',
      'auth.diaspora': 'Diaspora',
      'auth.terms': 'Conditions'
    }
  }
};

i18n.use(LanguageDetector).use(initReactI18next).init({
  resources,
  fallbackLng: 'fr',
  lng: 'fr',
  interpolation: { escapeValue: false }
});

export default i18n;
